      if 2 * min_val <= max_val:
        break # Condition met, this segment is not valid, break inner loop
      # If we reach here, the current segment (arr[start:end+1]) is valid
      # Check if it's the longest valid segment found so far
      current_segment_length = end - start + 1
      longest_segment_length = longest_end - longest_start + 1
      if current_segment_length > longest_segment_length or longest_start == -1:
